import { db, type DocumentRow, type LessonPlanRow } from '../db.ts'
import { generatePlan } from '../ai/plan.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

type Difficulty = 'beginner' | 'intermediate' | 'advanced'
type PlanStatus = 'draft' | 'approved' | 'completed'

interface Objective {
  text: string
  topic: string
}

export async function createPlan(documentId: number) {
  const doc = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(documentId) as DocumentRow | undefined
  if (!doc) throw new NotFoundError('Document not found')
  if (doc.status !== 'ready' || !doc.markdown) {
    throw new BadRequestError(`Document is not ready for plan generation (status: ${doc.status})`)
  }

  const plan = await generatePlan(doc.markdown, doc.filename)
  const objectivesJson = JSON.stringify(plan.objectives)
  const res = db
    .prepare(
      `INSERT INTO lesson_plans (document_id, title, description, objectives, difficulty, status)
       VALUES (?, ?, ?, ?, ?, 'draft')
       RETURNING *`
    )
    .get(documentId, plan.title, plan.description, objectivesJson, plan.difficulty) as LessonPlanRow

  return {
    id: res.id,
    document_id: documentId,
    title: res.title,
    description: res.description,
    difficulty: res.difficulty as Difficulty,
    objectives: plan.objectives,
    status: res.status as PlanStatus,
    created_at: res.created_at
  }
}

export async function getPlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) return null
  const doc = db.prepare(`SELECT filename FROM documents WHERE id = ?`).get(row.document_id) as { filename: string }

  return {
    id: row.id,
    document_id: row.document_id,
    document_filename: doc.filename,
    title: row.title,
    description: row.description,
    difficulty: row.difficulty as Difficulty,
    objectives: JSON.parse(row.objectives) as Objective[],
    status: row.status as PlanStatus,
    created_at: row.created_at
  }
}

export async function getPlansForDocument(documentId: number) {
  const rows = db
    .prepare(`SELECT * FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC`)
    .all(documentId) as LessonPlanRow[]
  return rows.map((row) => ({
    id: row.id,
    document_id: row.document_id,
    title: row.title,
    description: row.description,
    difficulty: row.difficulty as Difficulty,
    objectives: JSON.parse(row.objectives) as Objective[],
    status: row.status as PlanStatus,
    created_at: row.created_at
  }))
}

export async function approvePlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) throw new NotFoundError('Plan not found')
  if (row.status === 'draft') {
    db.prepare(`UPDATE lesson_plans SET status = 'approved' WHERE id = ?`).run(planId)
  }
  return getPlan(planId)
}

import { db, type QuizQuestionRow } from '../db.ts'
import { generateQuiz } from '../ai/quiz.ts'
import { generateRetryHint, explainCorrect, aiChat } from '../ai/feedback.ts'
import { getPlan } from './plans.ts'
import { getDocumentMarkdown } from './documents.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

export interface QuizDTO {
  id: number
  objectiveIndex: number
  objectiveText: string
  question: string
  options: string[]
  hint: string
}

export async function getOrCreateQuiz(planId: number, objectiveIndex: number): Promise<QuizDTO> {
  const plan = await getPlan(planId)
  if (!plan) throw new NotFoundError('Plan not found')
  const objective = plan.objectives[objectiveIndex]
  if (!objective) throw new NotFoundError(`Objective ${objectiveIndex} not found`)

  const existing = db
    .prepare(`SELECT * FROM quiz_questions WHERE lesson_plan_id = ? AND objective_index = ?`)
    .get(planId, objectiveIndex) as QuizQuestionRow | undefined

  if (existing) {
    return {
      id: existing.id,
      objectiveIndex: existing.objective_index,
      objectiveText: existing.objective_text,
      question: existing.question,
      options: JSON.parse(existing.options),
      hint: existing.hint
    }
  }

  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const quiz = await generateQuiz(markdown, objective.text, objective.topic)

  const res = db
    .prepare(
      `INSERT INTO quiz_questions (lesson_plan_id, objective_index, objective_text, question, options, correct_index, explanation, hint)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)
       RETURNING id`
    )
    .get(
      planId,
      objectiveIndex,
      objective.text,
      quiz.question,
      JSON.stringify(quiz.options),
      quiz.correct_index,
      quiz.explanation,
      quiz.hint
    ) as { id: number }

  return {
    id: res.id,
    objectiveIndex,
    objectiveText: objective.text,
    question: quiz.question,
    options: quiz.options,
    hint: quiz.hint
  }
}

export async function getAllQuizzes(planId: number): Promise<QuizDTO[]> {
  const plan = await getPlan(planId)
  if (!plan) return []
  const rows = db
    .prepare(`SELECT * FROM quiz_questions WHERE lesson_plan_id = ? ORDER BY objective_index ASC`)
    .all(planId) as QuizQuestionRow[]
  return rows.map((r) => ({
    id: r.id,
    objectiveIndex: r.objective_index,
    objectiveText: r.objective_text,
    question: r.question,
    options: JSON.parse(r.options),
    hint: r.hint
  }))
}

export async function getQuizInternal(quizId: number): Promise<QuizQuestionRow | null> {
  return (db.prepare(`SELECT * FROM quiz_questions WHERE id = ?`).get(quizId) as QuizQuestionRow | undefined) ?? null
}

export async function getHint(quizId: number, previousGuessIndex: number | null): Promise<string> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  return generateRetryHint(
    markdown,
    quiz.question,
    options,
    previousGuessIndex !== null ? options[previousGuessIndex] : null
  )
}

interface ExplanationResult {
  explanation: string
  correctIndex: number
}

export async function getExplanation(quizId: number): Promise<ExplanationResult> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  const correct = options[quiz.correct_index]
  const explanation = await explainCorrect(markdown, quiz.question, options, correct, quiz.correct_index)
  return { explanation, correctIndex: quiz.correct_index }
}

export interface AnswerOutput {
  correct: boolean
}

export async function checkAnswer(quizId: number, learnerIndex: number): Promise<AnswerOutput> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const correct = learnerIndex === quiz.correct_index
  return { correct }
}

interface AI_Message {
  role: 'user' | 'assistant'
  content: string
}
export type MessageHistory = Array<AI_Message>

export async function getAiHelp(id: number, question: string, history: MessageHistory): Promise<string> {
  const quiz = await getQuizInternal(id)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  return aiChat(markdown, quiz.question, options, question, history)
}

import path from 'node:path'
import { unlink } from 'node:fs/promises'
import { nanoid } from 'nanoid'
import { db, type DocumentRow } from '../db.ts'
import { convertPdfToMarkdown } from './pdf-to-markdown.ts'
import { UPLOADS_DIR } from '../config.ts'

type DocumentListItem = Omit<DocumentRow, 'stored_filename' | 'filepath' | 'markdown'>

interface PlanSummaryRow {
  id: number
  difficulty: string
  status: string
}

export async function listDocuments() {
  const rows = db
    .prepare(
      `SELECT id, filename, title, markdown_chars, status, error, created_at
       FROM documents ORDER BY datetime(created_at) DESC`
    )
    .all() as DocumentListItem[]

  return rows.map((r) => {
    const planRow = db
      .prepare(
        `SELECT id, difficulty, status FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC LIMIT 1`
      )
      .get(r.id) as PlanSummaryRow | undefined

    const attemptResult = db
      .prepare(
        `SELECT COUNT(*) AS c FROM attempts a JOIN lesson_plans p ON p.id = a.lesson_plan_id WHERE p.document_id = ?`
      )
      .get(r.id) as { c: number }

    const attemptCount = attemptResult.c
    return {
      ...r,
      plan: planRow
        ? {
            id: planRow.id,
            difficulty: planRow.difficulty,
            status: planRow.status
          }
        : null,
      attemptCount
    }
  })
}

export async function getDocument(id: number) {
  const row = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(id) as DocumentRow | undefined
  if (!row) return null
  return {
    id: row.id,
    filename: row.filename,
    title: row.title,
    status: row.status,
    markdown_chars: row.markdown_chars,
    created_at: row.created_at,
    error: row.error
  }
}

type Markdown = { markdown: string | null } | undefined

export async function getDocumentMarkdown(id: number): Promise<string | null> {
  const row = db.prepare(`SELECT markdown FROM documents WHERE id = ?`).get(id) as Markdown
  return row?.markdown ?? null
}

export async function uploadAndConvert(filename: string, buffer: Buffer): Promise<DocumentRow> {
  const storedFilename = `${Date.now()}-${nanoid(8)}-${filename.replace(/[^a-zA-Z0-9.\-_ ]/g, '')}`
  const filepath = path.join(UPLOADS_DIR, storedFilename)
  const { writeFile } = await import('node:fs/promises')
  await writeFile(filepath, buffer)

  const doc = db
    .prepare(
      `INSERT INTO documents (filename, stored_filename, filepath, status)
       VALUES (?, ?, ?, 'processing')
       RETURNING *`
    )
    .get(filename, storedFilename, filepath) as DocumentRow

  const result = await convertPdfToMarkdown(filepath)
  if (!result.ok) {
    db.prepare(`UPDATE documents SET status = 'failed', error = ? WHERE id = ?`).run(
      result.error ?? 'Unknown error',
      doc.id
    )
    throw Error('Error occured while converting PDF to markdown')
  }

  db.prepare(`UPDATE documents SET status = 'ready', markdown = ?, markdown_chars = ?, error = NULL WHERE id = ?`).run(
    result.markdown,
    result.markdown.length,
    doc.id
  )
  return doc
}

export async function deleteDocument(id: number): Promise<boolean> {
  const row = db.prepare(`SELECT filepath FROM documents WHERE id = ?`).get(id) as { filepath: string } | undefined
  if (!row) return false

  try {
    await unlink(row.filepath)
  } catch {
    // File may already be missing; proceed with DB cleanup
  }

  db.prepare(`DELETE FROM documents WHERE id = ?`).run(id)
  return true
}

import { db, type AttemptRow } from '../db.ts'
import { generateSummary, type AttemptInput } from '../ai/summary.ts'
import { getPlan } from './plans.ts'
import { getQuizInternal } from './quizzes.ts'
import { getDocumentMarkdown } from './documents.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

interface AttemptSummaryDTO {
  score: number
  total: number
  summary: string
  studyTips: string[]
  weakTopics: string[]
  strengths: string[]
  answers: Array<Answer>
}

interface Answer {
  question: string
  options: string[]
  correctIndex: number
  learnerIndex: number | null
  attempts: number
  objectiveText: string
}

interface AttemptAnswer {
  quizId: number
  learnerIndex: number | null
  attempts: number
}

export async function completeAttempt(
  planId: number,
  payload: { answers: AttemptAnswer[] }
): Promise<AttemptSummaryDTO> {
  const plan = await getPlan(planId)
  if (!plan) throw new NotFoundError('Plan not found')

  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')

  const questions: AttemptInput['questions'] = []
  let score = 0
  for (const ans of payload.answers) {
    const quiz = await getQuizInternal(ans.quizId)
    if (!quiz || quiz.lesson_plan_id !== planId) continue
    const options = JSON.parse(quiz.options) as string[]
    const correct = ans.learnerIndex === quiz.correct_index
    if (correct) score += 1
    questions.push({
      objectiveText: quiz.objective_text,
      question: quiz.question,
      options,
      correctIndex: quiz.correct_index,
      learnerIndex: ans.learnerIndex,
      attempts: ans.attempts
    })
  }

  const objectives = plan.objectives.map((o) => ({ text: o.text, topic: o.topic }))
  const summary = await generateSummary({ objectives, questions, markdown })

  const params = [
    planId,
    score,
    questions.length,
    JSON.stringify(payload.answers),
    summary.summary,
    JSON.stringify(summary.study_tips),
    JSON.stringify(summary.weak_topics),
    JSON.stringify(summary.strengths)
  ]
  db
    .prepare(
      `INSERT INTO attempts (lesson_plan_id, score, total, answers, summary, study_tips, weak_topics, strengths)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?)
     RETURNING id`
    )
    .get(params) as { id: number }

  db.prepare(`UPDATE lesson_plans SET status = 'completed' WHERE id = ?`).run(planId)

  return {
    score,
    total: questions.length,
    summary: summary.summary,
    studyTips: summary.study_tips,
    weakTopics: summary.weak_topics,
    strengths: summary.strengths,
    answers: questions.map((q) => ({
      question: q.question,
      options: q.options,
      correctIndex: q.correctIndex,
      learnerIndex: q.learnerIndex,
      attempts: q.attempts,
      objectiveText: q.objectiveText
    }))
  }
}

export async function listAttempts(planId: number) {
  const rows = db
    .prepare(`SELECT * FROM attempts WHERE lesson_plan_id = ? ORDER BY datetime(created_at) DESC`)
    .all(planId) as AttemptRow[]
  return rows.map((r) => ({
    id: r.id,
    lesson_plan_id: r.lesson_plan_id,
    score: r.score,
    total: r.total,
    summary: r.summary,
    study_tips: JSON.parse(r.study_tips) as string[],
    created_at: r.created_at
  }))
}

interface AnswerData {
  quizId: number
  learnerIndex: number | null
  attempts: number
}

export async function getAttempt(attemptId: number) {
  const row = db.prepare(`SELECT * FROM attempts WHERE id = ?`).get(attemptId) as AttemptRow | undefined
  if (!row) return null
  const answers = JSON.parse(row.answers) as Array<AnswerData>
  const quizzes = await Promise.all(
    answers.map(async (a) => {
      const quiz = await getQuizInternal(a.quizId)
      if (!quiz) return null
      return {
        question: quiz.question,
        options: JSON.parse(quiz.options) as string[],
        correctIndex: quiz.correct_index,
        learnerIndex: a.learnerIndex,
        attempts: a.attempts,
        objectiveText: quiz.objective_text
      }
    })
  )
  return {
    score: row.score,
    total: row.total,
    summary: row.summary,
    studyTips: JSON.parse(row.study_tips) as string[],
    weakTopics: JSON.parse(row.weak_topics) as string[],
    strengths: JSON.parse(row.strengths) as string[],
    answers: quizzes.filter(Boolean) as AttemptSummaryDTO['answers']
  }
}

