import { useCallback, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Sparkles, Loader2 } from 'lucide-react'
import { UploadDropzone } from '#components/upload-dropzone'
import { listDocuments, createPlan } from '#lib/api'

export function LibraryPage() {
  const [planning, setPlanning] = useState<number | null>(null)
  const [planError, setPlanError] = useState<string | null>(null)
  const navigate = useNavigate()

  const handleUploaded = useCallback(
    async (documentId: number) => {
      setPlanning(documentId)
      setPlanError(null)
      try {
        let docs = await listDocuments()
        let doc = docs.find((d) => d.id === documentId)
        while (doc && doc.status === 'processing') {
          await new Promise((r) => setTimeout(r, 1000))
          docs = await listDocuments()
          doc = docs.find((d) => d.id === documentId)
        }
        if (!doc || doc.status === 'failed') {
          throw new Error('Document processing failed')
        }
        const plan = await createPlan(documentId)
        navigate(`/learn/${plan.id}`)
      } catch (err) {
        console.error('Failed to create plan after upload:', err)
        setPlanError((err as Error).message ?? 'Failed to create lesson plan')
      } finally {
        setPlanning(null)
      }
    },
    [navigate]
  )

  return (
    <div className="space-y-10">
      <section className="relative overflow-hidden rounded-3xl border border-border bg-card p-8 sm:p-12">
        <div className="absolute inset-0 bg-grid-pattern opacity-60" />
        <div className="absolute inset-0 bg-radial-glow" />
        <div className="relative z-10 max-w-2xl">
          <span className="inline-flex items-center gap-1.5 rounded-full border border-primary/30 bg-primary/10 px-3 py-1 text-xs font-medium text-primary">
            <Sparkles className="size-3.5" />
            Human-in-the-loop learning agent
          </span>
          <h1 className="mt-4 text-3xl font-bold tracking-tight sm:text-4xl">
            Turn any PDF into an interactive lesson.
          </h1>
          <p className="mt-3 text-base text-muted-foreground">
            Upload a document, review the proposed learning path, then learn by answering quizzes with instant feedback,
            hints, and explanations — grounded in your PDF.
          </p>
          <div className="mt-6">
            <UploadDropzone onUploaded={handleUploaded} />
          </div>
        </div>
      </section>

      {planning !== null && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/70 backdrop-blur-sm">
          <div className="flex items-center gap-3 rounded-2xl border border-border bg-card px-6 py-4 shadow-xl">
            <Loader2 className="size-5 animate-spin text-primary" />
            <div>
              <p className="text-sm font-medium">Drafting your lesson plan...</p>
              <p className="text-xs text-muted-foreground">Analyzing the PDF content with the agent.</p>
            </div>
          </div>
        </div>
      )}

      {planError && (
        <div className="fixed bottom-4 right-4 z-50 max-w-sm rounded-2xl border border-danger/30 bg-danger/10 px-4 py-3 text-sm text-danger backdrop-blur-sm">
          <p className="font-medium">Plan creation failed</p>
          <p className="mt-1 text-xs text-danger/80">{planError}</p>
          <button onClick={() => setPlanError(null)} className="mt-2 text-xs underline hover:text-danger">
            Dismiss
          </button>
        </div>
      )}
    </div>
  )
}

import { useCallback, useEffect, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { ArrowLeft, Loader2 } from 'lucide-react'
import { PlanCard } from '#components/plan-card'
import { MCQWidget } from '#components/mcq-widget'
import { ObjectiveTracker, type ObjectiveStatus } from '#components/objective-tracker'
import { SummaryView } from '#components/summary-view'
import { Card, CardContent } from '#components/ui/card'
import { Progress } from '#components/ui/progress'
import { approvePlan, completeAttempt, generateQuiz, getAttempt, getPlan, listAttempts, listQuizzes } from '#lib/api'
import type { AttemptSummary, Plan, QuizDTO } from '#lib/types'
import { difficultyLabel } from '#lib/format'

type Phase = 'loading' | 'review' | 'quiz' | 'summary' | 'error'

interface AnswerState {
  quizId: number
  learnerIndex: number | null
  attempts: number
  correct: boolean
  finalized: boolean
}

function blankAnswer(quizId: number): AnswerState {
  return {
    quizId,
    learnerIndex: null,
    attempts: 0,
    correct: false,
    finalized: false
  }
}

export function LessonPage() {
  const { planId } = useParams<{ planId: string }>()
  const navigate = useNavigate()
  const [phase, setPhase] = useState<Phase>('loading')
  const [plan, setPlan] = useState<Plan | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [quizzes, setQuizzes] = useState<Record<number, QuizDTO>>({})
  const [answers, setAnswers] = useState<Record<number, AnswerState>>({})
  const [currentIdx, setCurrentIdx] = useState(0)
  const [loadingQuiz, setLoadingQuiz] = useState(false)
  const [summary, setSummary] = useState<AttemptSummary | null>(null)
  const [finishing, setFinishing] = useState(false)

  useEffect(() => {
    if (!planId) return
    const id = Number(planId)

    async function loadPlan() {
      const p = await getPlan(id)
      setPlan(p)

      if (p.status === 'draft') {
        setPhase('review')
        return
      }

      if (p.status !== 'completed') {
        setPhase('quiz')
        return
      }

      try {
        const attempts = await listAttempts(id)
        if (attempts.length === 0) {
          setPhase('quiz')
          return
        }
        const latest = await getAttempt(attempts[0].id)
        setSummary(latest)
        setPhase('summary')
      } catch {
        setPhase('quiz')
      }
    }

    loadPlan().catch((err: unknown) => {
      setError((err as Error).message)
      setPhase('error')
    })
  }, [planId])

  // Preload cached quizzes when entering the quiz phase (retest path)
  useEffect(() => {
    if (phase !== 'quiz' || !planId || !plan) return
    const id = Number(planId)
    listQuizzes(id)
      .then((existing) => {
        if (existing.length === 0) return
        const map: Record<number, QuizDTO> = {}
        for (const q of existing) map[q.objectiveIndex] = q
        setQuizzes(map)
      })
      .catch(() => {
        // ignore — we'll lazy-generate
      })
  }, [phase, planId, plan])

  const currentQuiz = quizzes[currentIdx]

  // Lazy-generate the quiz for the current objective when needed
  useEffect(() => {
    if (phase !== 'quiz' || !plan || !planId) return
    if (quizzes[currentIdx] || loadingQuiz) return
    if (currentIdx >= plan.objectives.length) return
    const id = Number(planId)
    setLoadingQuiz(true)
    generateQuiz(id, currentIdx)
      .then((q) => {
        setQuizzes((prev) => ({ ...prev, [currentIdx]: q }))
      })
      .catch((err: unknown) => {
        setError((err as Error).message)
        setPhase('error')
      })
      .finally(() => setLoadingQuiz(false))
  }, [phase, plan, planId, currentIdx, quizzes, loadingQuiz])

  const handleApprove = useCallback(async () => {
    if (!plan) return
    try {
      const updated = await approvePlan(plan.id)
      setPlan(updated)
      setPhase('quiz')
    } catch (err) {
      setError((err as Error).message)
      setPhase('error')
    }
  }, [plan])

  const handleIncorrect = useCallback(
    (idx: number, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[idx]?.id ?? -1
        const existing = prev[idx] ?? blankAnswer(quizId)
        return {
          ...prev,
          [idx]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: false,
            attempts: existing.attempts + 1,
            finalized: false
          }
        }
      })
    },
    [quizzes]
  )

  const handleCorrect = useCallback(
    (idx: number, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[idx]?.id ?? -1
        const existing = prev[idx] ?? blankAnswer(quizId)
        return {
          ...prev,
          [idx]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: true,
            // attempts stays — counts only incorrect tries
            finalized: true
          }
        }
      })
    },
    [quizzes]
  )

  const handleSkip = useCallback(
    (idx: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[idx]?.id ?? -1
        const existing = prev[idx] ?? blankAnswer(quizId)
        return {
          ...prev,
          [idx]: {
            ...existing,
            quizId,
            learnerIndex: null,
            correct: false,
            finalized: true
          }
        }
      })
      setCurrentIdx((i) => i + 1)
    },
    [quizzes]
  )

  const finish = useCallback(async () => {
    if (!plan || !planId || finishing) return
    setFinishing(true)
    try {
      const payload = Object.values(answers).map((a) => ({
        quizId: a.quizId,
        learnerIndex: a.learnerIndex,
        attempts: a.attempts
      }))
      const result = await completeAttempt(plan.id, payload)
      setSummary(result)
      setPhase('summary')
    } catch (err) {
      setError((err as Error).message)
      setPhase('error')
    } finally {
      setFinishing(false)
    }
  }, [plan, planId, answers, finishing])

  const advance = useCallback(() => {
    if (!plan) return
    if (currentIdx + 1 >= plan.objectives.length) {
      void finish()
    } else {
      setCurrentIdx((i) => i + 1)
    }
  }, [currentIdx, plan, finish])

  const handleRetake = useCallback(() => {
    setAnswers({})
    setQuizzes({})
    setCurrentIdx(0)
    setSummary(null)
    setPhase('quiz')
  }, [])

  if (phase === 'loading') {
    return (
      <div className="flex h-[60vh] items-center justify-center">
        <Loader2 className="size-6 animate-spin text-primary" />
      </div>
    )
  }

  if (phase === 'error' || !plan) {
    return (
      <div className="mx-auto max-w-2xl">
        <Card>
          <CardContent className="p-8 text-center">
            <p className="text-sm font-medium text-danger">{error ?? 'Something went wrong.'}</p>
          </CardContent>
        </Card>
      </div>
    )
  }

  if (phase === 'review') {
    return <PlanCard plan={plan} onApprove={handleApprove} onBack={() => navigate('/')} />
  }

  if (phase === 'summary' && summary) {
    return <SummaryView summary={summary} onRetake={handleRetake} onBackToLibrary={() => navigate('/')} />
  }

  // quiz phase
  const total = plan.objectives.length
  const answerList = plan.objectives.map((_, i) => answers[i])
  const completed = answerList.filter((a) => a?.finalized).length
  const score = answerList.filter((a) => a?.correct).length
  const progressPct = total === 0 ? 0 : Math.round((completed / total) * 100)
  const statuses: ObjectiveStatus[] = plan.objectives.map((_, i) => {
    const a = answers[i]
    if (a?.finalized) {
      return a.correct ? 'correct' : 'skipped'
    }
    if (i === currentIdx) return 'current'
    return 'pending'
  })

  return (
    <div className="space-y-6">
      <div className="space-y-2">
        <div className="flex items-center justify-between gap-3">
          <div className="min-w-0">
            <h1 className="truncate text-xl font-bold tracking-tight">{plan.title}</h1>
            <p className="text-xs text-muted-foreground">
              {difficultyLabel(plan.difficulty)} · {completed} of {total} objectives done
            </p>
          </div>
          <div className="text-right">
            <p className="text-2xl font-bold tabular-nums">
              {score}
              <span className="text-base text-muted-foreground">/{total}</span>
            </p>
          </div>
        </div>
        <Progress value={progressPct} />
      </div>

      <div className="grid gap-6 lg:grid-cols-[1fr_280px]">
        <div className="min-w-0">
          {currentQuiz ? (
            <MCQWidget
              key={currentQuiz.id}
              quiz={currentQuiz}
              objectiveNumber={currentIdx + 1}
              totalObjectives={total}
              onCorrect={(learnerIndex) => {
                handleCorrect(currentIdx, learnerIndex)
              }}
              onIncorrect={(learnerIndex) => handleIncorrect(currentIdx, learnerIndex)}
              onSkip={() => handleSkip(currentIdx)}
              onNext={advance}
              isLast={currentIdx === total - 1}
            />
          ) : (
            <Card>
              <CardContent className="flex flex-col items-center justify-center gap-3 p-12 text-center">
                <Loader2 className="size-6 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">Generating question for objective {currentIdx + 1}...</p>
              </CardContent>
            </Card>
          )}
          {finishing && (
            <p className="mt-4 flex items-center justify-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="size-4 animate-spin" />
              Building your progress report...
            </p>
          )}
        </div>

        <aside className="lg:sticky lg:top-20 lg:self-start">
          <ObjectiveTracker objectives={plan.objectives} statuses={statuses} score={score} total={total} />
        </aside>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import Markdown from 'react-markdown'
import { Check, CircleAlert, HelpCircle, Lightbulb, Loader2, MessageSquareText, Send, X } from 'lucide-react'
import { cn } from '#lib/utils'
import { Badge } from '#components/ui/badge'
import { Button } from '#components/ui/button'
import { Card, CardContent } from '#components/ui/card'
import { RadioGroup, RadioGroupItem } from '#components/ui/radio-group'
import { Textarea } from '#components/ui/textarea'
import { checkAnswer, getExplanation, getHint, learnMore } from '#lib/api'
import type { ChatMessage, QuizDTO } from '#lib/types'

interface Props {
  quiz: QuizDTO
  objectiveNumber: number
  totalObjectives: number
  onCorrect: (learnerIndex: number) => void
  onIncorrect: (learnerIndex: number) => void
  onSkip: () => void
  onNext: () => void
  isLast: boolean
}

type Status = 'idle' | 'submitted' | 'correct' | 'incorrect'

export function MCQWidget({
  quiz,
  objectiveNumber,
  totalObjectives,
  onCorrect,
  onIncorrect,
  onSkip,
  onNext,
  isLast
}: Props) {
  const [selected, setSelected] = useState<number | null>(null)
  const [status, setStatus] = useState<Status>('idle')
  const [submitting, setSubmitting] = useState(false)
  const [hint, setHint] = useState<string | null>(null)
  const [hintLoading, setHintLoading] = useState(false)
  const [explanation, setExplanation] = useState<string | null>(null)
  const [showExplanation, setShowExplanation] = useState(false)
  const [explanationLoading, setExplanationLoading] = useState(false)
  const [tries, setTries] = useState(0)
  const [chatOpen, setChatOpen] = useState(false)

  // Reset state when quiz changes (new objective)
  useEffect(() => {
    setSelected(null)
    setStatus('idle')
    setHint(null)
    setExplanation(null)
    setShowExplanation(false)
    setTries(0)
    setChatOpen(false)
  }, [quiz.id])

  const submit = async () => {
    if (selected === null || submitting) return
    setHint(null)
    setSubmitting(true)
    try {
      const res = await checkAnswer(quiz.id, selected)
      if (res.correct) {
        setStatus('correct')
        onCorrect(selected)
      } else {
        setStatus('incorrect')
        onIncorrect(selected)
        setTries((t) => t + 1)
      }
    } finally {
      setSubmitting(false)
    }
  }

  const retry = () => {
    setStatus('idle')
    setSelected(null)
    setHint(null)
  }

  const requestHint = async () => {
    setHintLoading(true)
    try {
      const res = await getHint(quiz.id, status === 'incorrect' ? selected : null)
      setHint(res.hint)
    } finally {
      setHintLoading(false)
    }
  }

  const locked = status === 'correct'

  return (
    <Card className="overflow-hidden">
      <CardContent className="p-0">
        <div className="border-b border-border bg-accent/40 px-5 py-3 sm:px-6">
          <div className="flex items-center justify-between gap-3">
            <div className="min-w-0">
              <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
                Objective {objectiveNumber} of {totalObjectives}
              </p>
              <p className="mt-0.5 truncate text-sm font-semibold">{quiz.objectiveText}</p>
            </div>
            {tries > 0 && status !== 'correct' && (
              <Badge variant="destructive">
                {tries} {tries === 1 ? 'miss' : 'misses'}
              </Badge>
            )}
            {status === 'correct' && (
              <Badge variant="default">
                <Check className="size-3" />
                Correct
              </Badge>
            )}
          </div>
        </div>

        <div className="space-y-5 p-5 sm:p-6">
          <p className="text-base font-medium leading-relaxed">{quiz.question}</p>

          <RadioGroup
            value={selected !== null ? String(selected) : undefined}
            onValueChange={(v) => {
              if (locked) return
              const next = Number(v)
              setSelected(next)
              if (status === 'incorrect') {
                setStatus('idle')
                setHint(null)
              }
            }}
            className="gap-2.5"
          >
            {quiz.options.map((opt, i) => {
              const isSelected = selected === i
              const showAsCorrect = locked && isSelected
              const showAsWrong = status === 'incorrect' && isSelected
              return (
                <label
                  key={i}
                  className={cn(
                    'flex items-center gap-3 rounded-xl border p-3.5 text-sm transition-all',
                    locked ? 'cursor-default' : 'cursor-pointer',
                    !locked && 'hover:border-primary/50 hover:bg-accent/50',
                    isSelected && !locked ? 'border-primary bg-primary/5' : 'border-border bg-card',
                    showAsCorrect && 'border-success/60 bg-success/10 text-success',
                    showAsWrong && 'border-danger/60 bg-danger/10 text-danger'
                  )}
                >
                  <RadioGroupItem
                    value={String(i)}
                    disabled={locked}
                    className={cn(
                      showAsCorrect &&
                        'border-success text-success data-[checked]:bg-success data-[checked]:border-success',
                      showAsWrong && 'border-danger text-danger data-[checked]:bg-danger data-[checked]:border-danger'
                    )}
                  />
                  <span className="flex-1 leading-relaxed">{opt}</span>
                  {showAsCorrect && <Check className="size-4 shrink-0" />}
                  {showAsWrong && <X className="size-4 shrink-0" />}
                </label>
              )
            })}
          </RadioGroup>

          {status === 'incorrect' && (
            <div className="flex items-start gap-2.5 rounded-xl border border-danger/40 bg-danger/10 p-3.5 text-sm">
              <CircleAlert className="size-4 shrink-0 translate-y-0.5 text-danger" />
              <div>
                <p className="font-medium text-danger">Not quite.</p>
                <p className="mt-0.5 text-muted-foreground">
                  Try again — you can request a hint or ask for a deeper explanation. No penalty for retries.
                </p>
              </div>
            </div>
          )}

          {hint && (
            <div className="flex items-start gap-2.5 rounded-xl border border-primary/30 bg-primary/5 p-3.5 text-sm">
              <Lightbulb className="size-4 shrink-0 translate-y-0.5 text-primary" />
              <div>
                <p className="font-medium text-primary">Hint</p>
                <p className="mt-0.5 text-foreground">{hint}</p>
              </div>
            </div>
          )}

          {status === 'correct' && showExplanation && explanation && (
            <div className="flex items-start gap-2.5 rounded-xl border border-success/40 bg-success/10 p-3.5 text-sm">
              <Check className="size-4 shrink-0 translate-y-0.5 text-success" />
              <div>
                <p className="font-medium text-success">Explanation</p>
                <p className="mt-0.5 text-foreground">{explanation}</p>
              </div>
            </div>
          )}

          <div className="flex flex-wrap items-center gap-2 pt-1">
            {!locked && (
              <>
                <Button onClick={submit} disabled={selected === null || submitting} className="gap-1.5">
                  {submitting ? <Loader2 className="size-4 animate-spin" /> : <Send className="size-4" />}
                  {status === 'incorrect' ? 'Re-submit' : 'Submit answer'}
                </Button>
                <Button variant="outline" onClick={requestHint} disabled={hintLoading} className="gap-1.5">
                  {hintLoading ? <Loader2 className="size-4 animate-spin" /> : <HelpCircle className="size-4" />}
                  {hint ? 'New hint' : 'Get a hint'}
                </Button>
                <Button variant="ghost" onClick={() => setChatOpen(true)} className="gap-1.5">
                  <MessageSquareText className="size-4" />
                  AI Help
                </Button>
                {status === 'incorrect' && (
                  <Button variant="ghost" onClick={retry} className="ml-auto">
                    Reset selection
                  </Button>
                )}
                {status === 'incorrect' && tries >= 1 && (
                  <Button variant="ghost" onClick={onSkip} className="text-muted-foreground">
                    Skip →
                  </Button>
                )}
              </>
            )}
            {locked && (
              <>
                <Button
                  variant="outline"
                  onClick={async () => {
                    if (showExplanation) {
                      setShowExplanation(false)
                      return
                    }
                    setExplanationLoading(true)
                    try {
                      const res = await getExplanation(quiz.id)
                      setExplanation(res.explanation)
                      setShowExplanation(true)
                    } finally {
                      setExplanationLoading(false)
                    }
                  }}
                  disabled={explanationLoading}
                  className="gap-1.5"
                >
                  {explanationLoading ? (
                    <Loader2 className="size-4 animate-spin" />
                  ) : showExplanation ? (
                    'Hide explanation'
                  ) : (
                    'Show explanation'
                  )}
                </Button>
                <Button onClick={onNext} className="ml-auto gap-1.5">
                  {isLast ? 'Finish & see results' : 'Next objective'}
                </Button>
              </>
            )}
          </div>
        </div>
      </CardContent>

      {chatOpen && <LearnMorePanel quiz={quiz} onClose={() => setChatOpen(false)} />}
    </Card>
  )
}

interface LearnMoreProps {
  quiz: QuizDTO
  onClose: () => void
}

function LearnMorePanel({ quiz, onClose }: LearnMoreProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'assistant',
      content:
        'I can dig deeper into the topic behind this question — without revealing the answer. Ask me anything about the concepts.'
    }
  ])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(false)

  const send = async () => {
    const q = input.trim()
    if (!q || loading) return
    const nextHistory: ChatMessage[] = [...messages, { role: 'user', content: q }]
    setMessages(nextHistory)
    setInput('')
    setLoading(true)
    try {
      const res = await learnMore(
        quiz.id,
        q,
        nextHistory.filter((m) => m.role !== 'assistant' || m.content !== messages[0]?.content)
      )
      setMessages((cur) => [...cur, { role: 'assistant', content: res.message }])
    } catch (err) {
      setMessages((cur) => [
        ...cur,
        {
          role: 'assistant',
          content: `Sorry, I couldn't fetch an answer right now: ${(err as Error).message}`
        }
      ])
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-end sm:items-center sm:justify-end">
      <div className="absolute inset-0 bg-background/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative flex h-[70vh] w-full max-w-md flex-col rounded-t-2xl border border-border bg-card shadow-2xl sm:rounded-2xl">
        <div className="flex items-center justify-between border-b border-border bg-accent/40 px-4 py-3">
          <div className="flex items-center gap-2">
            <span className="flex size-8 items-center justify-center rounded-lg bg-primary text-primary-foreground">
              <MessageSquareText className="size-4" />
            </span>
            <div>
              <p className="text-sm font-semibold">Ask the tutor</p>
              <p className="text-xs text-muted-foreground">Answers stay grounded in your PDF</p>
            </div>
          </div>
          <Button variant="ghost" size="icon-sm" onClick={onClose}>
            <X className="size-4" />
          </Button>
        </div>
        <div className="flex-1 space-y-3 overflow-y-auto p-4">
          {messages.map((m, i) => (
            <div key={i} className={cn('flex', m.role === 'user' ? 'justify-end' : 'justify-start')}>
                <div
                className={cn(
                  'max-w-[85%] rounded-2xl px-3.5 py-2 text-sm leading-relaxed',
                  m.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-accent text-accent-foreground'
                )}
              >
                {m.role === 'user' ? (
                  <span className="whitespace-pre-wrap">{m.content}</span>
                ) : (
                  <Markdown>{m.content}</Markdown>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex items-center gap-2 text-xs text-muted-foreground">
              <Loader2 className="size-3 animate-spin" />
              Thinking...
            </div>
          )}
        </div>
        <div className="border-t border-border p-3">
          <div className="flex items-end gap-2">
            <Textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about the concept..."
              className="min-h-[44px] flex-1 resize-none"
              rows={1}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault()
                  void send()
                }
              }}
            />
            <Button onClick={send} disabled={loading || !input.trim()} size="icon">
              <Send className="size-4" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  )
}

import { useNavigate } from 'react-router-dom'
import { Clock, FileText, Loader2, AlertTriangle, RefreshCw, ChevronRight, Layers, Trash2 } from 'lucide-react'
import { cn } from '#lib/utils'
import { Badge } from '#components/ui/badge'
import { Button } from '#components/ui/button'
import type { DocumentSummary } from '#lib/types'
import { difficultyLabel, formatDate } from '#lib/format'

interface Props {
  doc: DocumentSummary
  onStartLearning?: (documentId: number) => void
  onDelete?: (documentId: number) => void
}

export function DocumentCard({ doc, onStartLearning, onDelete }: Props) {
  const navigate = useNavigate()
  const ready = doc.status === 'ready'
  const processing = doc.status === 'processing'
  const failed = doc.status === 'failed'

  const start = () => {
    if (doc.plan) {
      navigate(`/learn/${doc.plan.id}`)
    } else if (onStartLearning) {
      onStartLearning(doc.id)
    }
  }

  const title = doc.title || doc.filename.replace(/\.pdf$/i, '')

  return (
    <div className="group flex flex-col rounded-2xl border border-border bg-card p-5 shadow-sm transition-all hover:shadow-md hover:border-primary/40">
      <div className="flex items-start gap-3">
        <div
          className={cn(
            'flex size-11 shrink-0 items-center justify-center rounded-xl',
            ready
              ? 'bg-primary/10 text-primary'
              : processing
                ? 'bg-accent text-accent-foreground'
                : 'bg-danger/10 text-danger'
          )}
        >
          {processing ? (
            <Loader2 className="size-5 animate-spin" />
          ) : failed ? (
            <AlertTriangle className="size-5" />
          ) : (
            <FileText className="size-5" />
          )}
        </div>
        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-semibold" title={title}>
            {title}
          </p>
          <p className="truncate text-xs text-muted-foreground" title={doc.filename}>
            {doc.filename}
          </p>
        </div>
        {doc.plan && <Badge variant="secondary">{difficultyLabel(doc.plan.difficulty)}</Badge>}
      </div>

      <div className="mt-4 flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
        <span className="inline-flex items-center gap-1">
          <Clock className="size-3.5" />
          {formatDate(doc.created_at)}
        </span>
        {ready && (
          <span className="inline-flex items-center gap-1">
            <FileText className="size-3.5" />
            {doc.markdown_chars.toLocaleString()} chars
          </span>
        )}
        {doc.attemptCount > 0 && (
          <span className="inline-flex items-center gap-1">
            <Layers className="size-3.5" />
            {doc.attemptCount} attempt{doc.attemptCount > 1 ? 's' : ''}
          </span>
        )}
      </div>

      {failed && (
        <p className="mt-3 line-clamp-2 rounded-md bg-danger/10 px-2.5 py-1.5 text-xs text-danger">
          {doc.error ?? 'Failed to process PDF'}
        </p>
      )}

      <div className="mt-4 flex items-center gap-2">
        {ready && !doc.plan && (
          <Button size="sm" className="gap-1.5" onClick={start}>
            Start learning
            <ChevronRight className="size-3.5" />
          </Button>
        )}
        {ready && doc.plan && (
          <>
            <Button size="sm" className="gap-1.5" onClick={start}>
              {doc.attemptCount > 0 ? (
                <>
                  <RefreshCw className="size-3.5" />
                  Retake
                </>
              ) : (
                <>
                  Continue
                  <ChevronRight className="size-3.5" />
                </>
              )}
            </Button>
            {doc.attemptCount > 0 && (
              <Button size="sm" variant="ghost" className="gap-1.5" onClick={start}>
                Review plan
              </Button>
            )}
          </>
        )}
        {processing && (
          <Button size="sm" variant="outline" disabled className="gap-1.5">
            <Loader2 className="size-3.5 animate-spin" />
            Parsing...
          </Button>
        )}
        {onDelete && (
          <Button
            size="sm"
            variant="ghost"
            className="ml-auto gap-1.5 text-danger hover:text-danger hover:bg-danger/10"
            onClick={() => {
              if (window.confirm(`Delete "${doc.title || doc.filename}"? This will remove all associated lesson plans and quiz attempts.`)) {
                onDelete(doc.id)
              }
            }}
          >
            <Trash2 className="size-3.5" />
          </Button>
        )}
      </div>
    </div>
  )
}

