  --success-foreground: oklch(0.16 0.02 260);
  --danger: oklch(0.7 0.22 27);
  --danger-foreground: oklch(0.16 0.02 260);
  --border: oklch(1 0 0 / 10%);
  --input: oklch(1 0 0 / 14%);
  --ring: oklch(0.62 0.2 264);
  --chart-1: oklch(0.62 0.2 264);
  --chart-2: oklch(0.65 0.16 220);
  --chart-3: oklch(0.7 0.15 280);
  --chart-4: oklch(0.55 0.1 220);
  --chart-5: oklch(0.45 0.2 264);
  --sidebar: oklch(0.19 0.025 260);
  --sidebar-foreground: oklch(0.97 0.005 250);
  --sidebar-primary: oklch(0.62 0.2 264);
  --sidebar-primary-foreground: oklch(0.16 0.02 260);
  --sidebar-accent: oklch(0.3 0.06 264);
  --sidebar-accent-foreground: oklch(0.97 0.005 250);
  --sidebar-border: oklch(1 0 0 / 10%);
  --sidebar-ring: oklch(0.62 0.2 264);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground antialiased;
  }
  html {
    @apply font-sans;
  }
}

@layer utilities {
  .bg-grid-pattern {
    background-image:
      linear-gradient(to right, color-mix(in oklch, var(--foreground) 6%, transparent) 1px, transparent 1px),
      linear-gradient(to bottom, color-mix(in oklch, var(--foreground) 6%, transparent) 1px, transparent 1px);
    background-size: 28px 28px;
  }
  .bg-radial-glow {
    background:
      radial-gradient(60% 50% at 50% 0%, color-mix(in oklch, var(--primary) 18%, transparent) 0%, transparent 70%),
      radial-gradient(40% 30% at 90% 10%, color-mix(in oklch, var(--primary) 12%, transparent) 0%, transparent 60%);
  }
}
